    text = data.content[0].text; provider = 'claude'; model = data.model || '';
  } else if (data.choices && Array.isArray(data.choices) && data.choices[0] && data.choices[0].message && data.choices[0].message.content) {
    text = data.choices[0].message.content; provider = 'hf'; model = data.model || '';
  } else if (data.error) {
    const em = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    throw new Error('Provider error: ' + String(em).slice(0, 300));
  } else {
    throw new Error('Unrecognized LLM response: ' + JSON.stringify(data).slice(0, 200));
  }
  let s = String(text || '').trim();
  s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/g, '').trim();
  const startObj = s.indexOf('{');
  const startArr = s.indexOf('[');
  let start;
  if (startObj === -1) start = startArr;
  else if (startArr === -1) start = startObj;
  else start = Math.min(startObj, startArr);
  if (start === -1) throw new Error('No JSON found: ' + s.slice(0, 200));
  const lastObj = s.lastIndexOf('}');
  const lastArr = s.lastIndexOf(']');
